    auto& pos = AsAbsolute();
    return pos.ToGfxPoint(aBasis);
  }

  // Else
  auto& point = AsRelative();
  auto cp = point.coord.ToGfxPoint(aBasis);
  if (point.reference == StyleControlReference::Start) {
