   102→                                       nsACString& aDest) const {
   103→  aDest.Append("calc("_ns);
   104→
   105→  bool written = false;
   106→
   107→  for (const RefPtr<CSSNumericValue>& value : mValues->GetValues()) {
   108→    if (value->IsCSSUnitValue()) {
   109→      CSSUnitValue& unitValue = value->GetAsCSSUnitValue();
   110→
   111→      if (written) {
   112→        aDest.Append(" + "_ns);
   113→      }
   114→
   115→      unitValue.ToCssTextWithProperty(aPropertyId, aDest);
   116→      written = true;
   117→    }
   118→
   119→    // TODO: Add support for other objects. See bug 2012324.
   120→  }
   121→
